module heating_system (
	input clk,
	input resetn,
	input too_cold,
	output reg heating);

	parameter OFF=0, ON=1;
	reg alt_state, next_state;

	always @(posedge clk) begin
		if (~resetn) alt_state <= OFF;
		else alt_state <= next_state;
	end

	always_comb begin
		case (alt_state)
			OFF: next_state = too_cold ? ON : OFF;
			ON: next_state = OFF;
			default: next_state = OFF;
		endcase
	end

	always @(alt_state) begin
		case (alt_state)
			ON: heating = 1;
			default: heating = 0;
		endcase
	end
endmodule
